func CopyFile(fs afero.Fs, from, to string) error {
	sf, err := fs.Open(from)
	if err != nil {
		return err
	}
	defer sf.Close()
	df, err := fs.Create(to)
	if err != nil {
		return err
	}
	defer df.Close()
	_, err = io.Copy(df, sf)
	if err != nil {
		return err
	}
	si, err := fs.Stat(from)
	if err != nil {
		err = fs.Chmod(to, si.Mode())

		if err != nil {
			return err
		}
	}

	return nil
}
